import{_ as i,o as a,c as e,ae as t}from"./chunks/framework.BD9pLfSD.js";const c=JSON.parse('{"title":"生成邀请链接","description":"","frontmatter":{},"headers":[],"relativePath":"2-experimenter-manual/5-invite-system/5-1-generate-invite.md","filePath":"2-experimenter-manual/5-invite-system/5-1-generate-invite.md"}'),r={name:"2-experimenter-manual/5-invite-system/5-1-generate-invite.md"};function o(n,l,s,h,u,p){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="生成邀请链接" tabindex="-1">生成邀请链接 <a class="header-anchor" href="#生成邀请链接" aria-label="Permalink to &quot;生成邀请链接&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>邀请链接是实验者邀请被试参与实验的重要工具。通过生成专属的邀请链接，您可以追踪邀请来源、管理被试注册，并获得平台奖励积分。每个实验者都有唯一的邀请链接，可以通过多种方式分享给潜在的被试。</p><h2 id="进入邀请页面" tabindex="-1">进入邀请页面 <a class="header-anchor" href="#进入邀请页面" aria-label="Permalink to &quot;进入邀请页面&quot;">​</a></h2><p>登录后，点击页面顶部导航栏的&quot;邀请用户&quot;即可进入邀请系统页面。</p><p><strong>注意</strong>：邀请功能仅对实验者角色开放。</p><h2 id="功能说明" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明" aria-label="Permalink to &quot;功能说明&quot;">​</a></h2><h3 id="_1-邀请链接生成" tabindex="-1">1. 邀请链接生成 <a class="header-anchor" href="#_1-邀请链接生成" aria-label="Permalink to &quot;1. 邀请链接生成&quot;">​</a></h3><h4 id="_1-1-自动生成" tabindex="-1">1.1 自动生成 <a class="header-anchor" href="#_1-1-自动生成" aria-label="Permalink to &quot;1.1 自动生成&quot;">​</a></h4><p><strong>生成时机</strong>：</p><ul><li>首次进入邀请页面时自动生成</li><li>每个实验者拥有唯一的邀请链接</li><li>链接永久有效，无需重复生成</li></ul><p><strong>邀请链接格式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://cogniand.com/register?ref={您的用户ID}&amp;code={邀请码}</span></span></code></pre></div><p><strong>邀请码特点</strong>：</p><ul><li>长度：8位字符</li><li>字符集：数字和大写字母</li><li>示例：<code>A3F7K9M2</code></li><li>唯一性：每个实验者的邀请码不同</li></ul><h4 id="_1-2-链接组成" tabindex="-1">1.2 链接组成 <a class="header-anchor" href="#_1-2-链接组成" aria-label="Permalink to &quot;1.2 链接组成&quot;">​</a></h4><p><strong>参数说明</strong>：</p><ol><li><p><strong>ref参数</strong>：</p><ul><li>您的用户ID</li><li>用于追踪邀请来源</li><li>关联邀请关系</li></ul></li><li><p><strong>code参数</strong>：</p><ul><li>唯一的邀请码</li><li>用于验证邀请有效性</li><li>防止恶意注册</li></ul></li></ol><h3 id="_2-查看邀请链接" tabindex="-1">2. 查看邀请链接 <a class="header-anchor" href="#_2-查看邀请链接" aria-label="Permalink to &quot;2. 查看邀请链接&quot;">​</a></h3><h4 id="_2-1-链接显示" tabindex="-1">2.1 链接显示 <a class="header-anchor" href="#_2-1-链接显示" aria-label="Permalink to &quot;2.1 链接显示&quot;">​</a></h4><p><strong>位置</strong>：页面左侧&quot;分享邀请链接&quot;区域</p><p><strong>显示方式</strong>：</p><ul><li>只读输入框</li><li>等宽字体显示</li><li>完整链接可见</li><li>支持选中复制</li></ul><h4 id="_2-2-复制链接" tabindex="-1">2.2 复制链接 <a class="header-anchor" href="#_2-2-复制链接" aria-label="Permalink to &quot;2.2 复制链接&quot;">​</a></h4><p><strong>操作步骤</strong>：</p><ol><li>找到邀请链接输入框</li><li>点击右侧的&quot;复制&quot;按钮</li><li>系统自动复制链接到剪贴板</li><li>按钮显示&quot;已复制&quot;状态（2秒后恢复）</li></ol><p><strong>复制成功标识</strong>：</p><ul><li>按钮图标从复制图标变为勾选图标</li><li>按钮文字变为&quot;已复制&quot;</li><li>2秒后自动恢复为&quot;复制&quot;状态</li></ul><p><strong>使用场景</strong>：</p><ul><li>复制后可粘贴到任何地方</li><li>通过即时通讯工具发送</li><li>添加到网站或论坛</li><li>保存到文档中</li></ul><h3 id="_3-邀请统计" tabindex="-1">3. 邀请统计 <a class="header-anchor" href="#_3-邀请统计" aria-label="Permalink to &quot;3. 邀请统计&quot;">​</a></h3><h4 id="_3-1-统计数据" tabindex="-1">3.1 统计数据 <a class="header-anchor" href="#_3-1-统计数据" aria-label="Permalink to &quot;3.1 统计数据&quot;">​</a></h4><p><strong>显示位置</strong>：页面左侧下方的统计卡片</p><p><strong>统计指标</strong>：</p><ol><li><p><strong>总邀请数</strong>：</p><ul><li>显示您发送的邀请总数</li><li>包括邮件邀请和链接分享</li><li>实时更新</li></ul></li><li><p><strong>成功注册</strong>：</p><ul><li>显示通过您的邀请成功注册的用户数</li><li>仅统计完成注册的用户</li><li>实时更新</li></ul></li></ol><h4 id="_3-2-查看详细历史" tabindex="-1">3.2 查看详细历史 <a class="header-anchor" href="#_3-2-查看详细历史" aria-label="Permalink to &quot;3.2 查看详细历史&quot;">​</a></h4><p><strong>操作步骤</strong>：</p><ol><li>在个人中心查看详细的邀请历史</li><li>包括邀请时间、邀请对象、注册状态等信息</li></ol><p>详细的邀请历史查看请参考<a href="/3-subject-manual/5-personal-center.html">个人中心</a>。</p><h3 id="_4-邀请链接的使用" tabindex="-1">4. 邀请链接的使用 <a class="header-anchor" href="#_4-邀请链接的使用" aria-label="Permalink to &quot;4. 邀请链接的使用&quot;">​</a></h3><h4 id="_4-1-分享方式" tabindex="-1">4.1 分享方式 <a class="header-anchor" href="#_4-1-分享方式" aria-label="Permalink to &quot;4.1 分享方式&quot;">​</a></h4><p><strong>直接分享</strong>：</p><ul><li>复制链接后直接发送给被试</li><li>通过微信、QQ、邮件等工具发送</li><li>添加到招募信息中</li></ul><p><strong>社交媒体分享</strong>：</p><ul><li>使用社交分享按钮快速分享</li><li>详细步骤请参考<a href="/2-experimenter-manual/5-invite-system/5-3-social-share.html">社交分享</a></li></ul><p><strong>邮件邀请</strong>：</p><ul><li>使用邮件邀请功能批量发送</li><li>详细步骤请参考<a href="/2-experimenter-manual/5-invite-system/5-2-send-email.html">邮件邀请</a></li></ul><h4 id="_4-2-被试注册流程" tabindex="-1">4.2 被试注册流程 <a class="header-anchor" href="#_4-2-被试注册流程" aria-label="Permalink to &quot;4.2 被试注册流程&quot;">​</a></h4><p><strong>被试点击链接后</strong>：</p><ol><li>自动跳转到注册页面</li><li>邀请码自动填充（不可见）</li><li>完成注册信息填写</li><li>提交注册</li><li>系统自动关联邀请关系</li></ol><p><strong>邀请关系建立</strong>：</p><ul><li>注册成功后自动建立邀请关系</li><li>您可以在统计中看到成功注册数增加</li><li>被试可以看到是通过您的邀请注册的</li></ul><h3 id="_5-邀请奖励" tabindex="-1">5. 邀请奖励 <a class="header-anchor" href="#_5-邀请奖励" aria-label="Permalink to &quot;5. 邀请奖励&quot;">​</a></h3><h4 id="_5-1-奖励机制" tabindex="-1">5.1 奖励机制 <a class="header-anchor" href="#_5-1-奖励机制" aria-label="Permalink to &quot;5.1 奖励机制&quot;">​</a></h4><p><strong>奖励条件</strong>：</p><ul><li>被试通过您的邀请链接成功注册</li><li>被试完成账户验证</li><li>被试参与至少一个实验</li></ul><p><strong>奖励内容</strong>：</p><ul><li>平台积分奖励</li><li>可用于兑换平台服务</li><li>具体奖励规则请查看平台公告</li></ul><h4 id="_5-2-查看奖励" tabindex="-1">5.2 查看奖励 <a class="header-anchor" href="#_5-2-查看奖励" aria-label="Permalink to &quot;5.2 查看奖励&quot;">​</a></h4><p><strong>查看方式</strong>：</p><ul><li>在个人中心查看积分余额</li><li>在邀请历史中查看每次邀请的奖励状态</li></ul><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><h3 id="_1-有效推广邀请链接" tabindex="-1">1. 有效推广邀请链接 <a class="header-anchor" href="#_1-有效推广邀请链接" aria-label="Permalink to &quot;1. 有效推广邀请链接&quot;">​</a></h3><p><strong>推广渠道</strong>：</p><ul><li>学术社交网络（ResearchGate、Academia.edu）</li><li>专业论坛和社区</li><li>学校公告板和邮件列表</li><li>社交媒体平台</li><li>个人网站或博客</li></ul><p><strong>推广技巧</strong>：</p><ul><li>说明平台的价值和特点</li><li>强调参与实验的意义</li><li>提供清晰的注册指引</li><li>回答潜在被试的疑问</li></ul><h3 id="_2-提高注册转化率" tabindex="-1">2. 提高注册转化率 <a class="header-anchor" href="#_2-提高注册转化率" aria-label="Permalink to &quot;2. 提高注册转化率&quot;">​</a></h3><p><strong>优化建议</strong>：</p><ul><li>在邀请信息中说明平台优势</li><li>提供实验参与的激励</li><li>简化注册流程说明</li><li>及时回复被试咨询</li></ul><p><strong>避免事项</strong>：</p><ul><li>不要发送垃圾邮件</li><li>不要在不相关的地方发布链接</li><li>不要使用误导性的宣传</li><li>不要强制他人注册</li></ul><h3 id="_3-管理邀请记录" tabindex="-1">3. 管理邀请记录 <a class="header-anchor" href="#_3-管理邀请记录" aria-label="Permalink to &quot;3. 管理邀请记录&quot;">​</a></h3><p><strong>记录管理</strong>：</p><ul><li>定期查看邀请统计</li><li>分析邀请效果</li><li>优化推广策略</li><li>跟进未完成注册的被试</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><p>⚠️ <strong>重要提示</strong>：</p><ol><li><p><strong>链接安全</strong></p><ul><li>不要将邀请链接分享给不可信的人</li><li>避免在公开场合泄露完整链接</li><li>如发现链接被滥用，请联系管理员</li></ul></li><li><p><strong>邀请规范</strong></p><ul><li>遵守平台使用规则</li><li>不得进行虚假邀请</li><li>不得使用自动化工具批量注册</li><li>违规行为可能导致账户被封禁</li></ul></li><li><p><strong>隐私保护</strong></p><ul><li>尊重被试的隐私</li><li>不要泄露被试的个人信息</li><li>遵守数据保护法规</li></ul></li><li><p><strong>邀请限制</strong></p><ul><li>邀请链接永久有效</li><li>无邀请数量限制</li><li>但需确保邀请的真实性和有效性</li></ul></li><li><p><strong>奖励规则</strong></p><ul><li>奖励规则可能随时调整</li><li>请关注平台公告</li><li>奖励发放可能有延迟</li></ul></li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q1-邀请链接会过期吗" tabindex="-1">Q1: 邀请链接会过期吗？ <a class="header-anchor" href="#q1-邀请链接会过期吗" aria-label="Permalink to &quot;Q1: 邀请链接会过期吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>不会，邀请链接永久有效</li><li>无需担心链接失效</li><li>可以长期使用同一个链接</li></ul><h3 id="q2-可以生成多个邀请链接吗" tabindex="-1">Q2: 可以生成多个邀请链接吗？ <a class="header-anchor" href="#q2-可以生成多个邀请链接吗" aria-label="Permalink to &quot;Q2: 可以生成多个邀请链接吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>不可以，每个实验者只有一个唯一的邀请链接</li><li>这样便于追踪和管理邀请关系</li><li>如需不同的推广渠道，可以使用邮件邀请功能</li></ul><h3 id="q3-如何知道有人通过我的链接注册了" tabindex="-1">Q3: 如何知道有人通过我的链接注册了？ <a class="header-anchor" href="#q3-如何知道有人通过我的链接注册了" aria-label="Permalink to &quot;Q3: 如何知道有人通过我的链接注册了？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>查看邀请统计中的&quot;成功注册&quot;数量</li><li>在个人中心查看详细的邀请历史</li><li>系统可能会发送通知（取决于设置）</li></ul><h3 id="q4-邀请奖励什么时候发放" tabindex="-1">Q4: 邀请奖励什么时候发放？ <a class="header-anchor" href="#q4-邀请奖励什么时候发放" aria-label="Permalink to &quot;Q4: 邀请奖励什么时候发放？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>被试完成注册并验证后自动发放</li><li>可能有1-3个工作日的延迟</li><li>在个人中心查看积分余额</li></ul><h3 id="q5-可以邀请已注册的用户吗" tabindex="-1">Q5: 可以邀请已注册的用户吗？ <a class="header-anchor" href="#q5-可以邀请已注册的用户吗" aria-label="Permalink to &quot;Q5: 可以邀请已注册的用户吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>不可以，邀请链接仅用于新用户注册</li><li>已注册用户点击链接会跳转到登录页面</li><li>不会建立邀请关系</li></ul><h3 id="q6-邀请链接被滥用怎么办" tabindex="-1">Q6: 邀请链接被滥用怎么办？ <a class="header-anchor" href="#q6-邀请链接被滥用怎么办" aria-label="Permalink to &quot;Q6: 邀请链接被滥用怎么办？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>立即联系平台管理员</li><li>提供滥用证据</li><li>管理员会调查并采取措施</li><li>可能会重新生成邀请链接</li></ul><h3 id="q7-可以修改邀请码吗" tabindex="-1">Q7: 可以修改邀请码吗？ <a class="header-anchor" href="#q7-可以修改邀请码吗" aria-label="Permalink to &quot;Q7: 可以修改邀请码吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>不可以，邀请码由系统自动生成</li><li>确保唯一性和安全性</li><li>如有特殊需求，请联系管理员</li></ul><h3 id="q8-邀请统计数据准确吗" tabindex="-1">Q8: 邀请统计数据准确吗？ <a class="header-anchor" href="#q8-邀请统计数据准确吗" aria-label="Permalink to &quot;Q8: 邀请统计数据准确吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>是的，统计数据实时更新</li><li>基于系统记录的实际数据</li><li>如发现数据异常，请联系技术支持</li></ul><h3 id="q9-可以取消邀请关系吗" tabindex="-1">Q9: 可以取消邀请关系吗？ <a class="header-anchor" href="#q9-可以取消邀请关系吗" aria-label="Permalink to &quot;Q9: 可以取消邀请关系吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>不可以，邀请关系一旦建立无法取消</li><li>这是为了保证数据的完整性</li><li>如有特殊情况，请联系管理员</li></ul><h3 id="q10-邀请链接可以用于商业推广吗" tabindex="-1">Q10: 邀请链接可以用于商业推广吗？ <a class="header-anchor" href="#q10-邀请链接可以用于商业推广吗" aria-label="Permalink to &quot;Q10: 邀请链接可以用于商业推广吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>需要遵守平台使用条款</li><li>商业推广需要获得平台授权</li><li>建议先咨询平台管理员</li><li>违规推广可能导致账户被封禁</li></ul><hr><p><strong>需要更多帮助？</strong> 请查看：</p><ul><li><a href="/2-experimenter-manual/5-invite-system/5-2-send-email.html">邮件邀请</a></li><li><a href="/2-experimenter-manual/5-invite-system/5-3-social-share.html">社交分享</a></li><li><a href="/3-subject-manual/5-personal-center.html">个人中心</a></li><li><a href="/7-technical-support/1-contact.html">技术支持</a></li></ul>',112)])])}const g=i(r,[["render",o]]);export{c as __pageData,g as default};
